CREATE TABLE IF NOT EXISTS service_prices (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,service_code VARCHAR(80) NOT NULL,service_name VARCHAR(160) NOT NULL,amount DECIMAL(12,2) NOT NULL,currency CHAR(3) NOT NULL DEFAULT 'KES',is_active BOOLEAN NOT NULL DEFAULT TRUE,updated_by BIGINT UNSIGNED NOT NULL,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,PRIMARY KEY(id),UNIQUE KEY uq_service_code(service_code),CONSTRAINT fk_price_admin FOREIGN KEY(updated_by) REFERENCES users(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS payment_methods (method_code VARCHAR(40) NOT NULL,display_name VARCHAR(100) NOT NULL,is_active BOOLEAN NOT NULL DEFAULT FALSE,configuration JSON NULL,updated_by BIGINT UNSIGNED NOT NULL,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,PRIMARY KEY(method_code),CONSTRAINT fk_payment_method_admin FOREIGN KEY(updated_by) REFERENCES users(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS password_reset_tokens (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,user_id BIGINT UNSIGNED NOT NULL,token_hash CHAR(64) NOT NULL,expires_at DATETIME NOT NULL,used_at DATETIME NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY(id),UNIQUE KEY uq_reset_hash(token_hash),KEY idx_reset_user(user_id,expires_at),CONSTRAINT fk_reset_user FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS candidate_documents (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,candidate_user_id BIGINT UNSIGNED NOT NULL,document_type ENUM('national_id','passport_photo','cv','certificate','recommendation','police_clearance','driving_licence') NOT NULL,storage_key VARCHAR(255) NOT NULL,original_name VARCHAR(255) NOT NULL,mime_type VARCHAR(100) NOT NULL,file_size INT UNSIGNED NOT NULL,status ENUM('uploaded','under_review','verified','rejected','expired') NOT NULL DEFAULT 'uploaded',reviewed_by BIGINT UNSIGNED NULL,reviewed_at DATETIME NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY(id),KEY idx_candidate_docs(candidate_user_id,document_type,status),CONSTRAINT fk_doc_candidate FOREIGN KEY(candidate_user_id) REFERENCES users(id) ON DELETE CASCADE,CONSTRAINT fk_doc_reviewer FOREIGN KEY(reviewed_by) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS candidate_verification_checks (candidate_user_id BIGINT UNSIGNED NOT NULL,check_code ENUM('phone_call','identity','passport_photo','cv','certificates','references','interview','availability') NOT NULL,status ENUM('pending','in_review','verified','needs_attention','not_required') NOT NULL DEFAULT 'pending',note VARCHAR(1000) NULL,updated_by BIGINT UNSIGNED NULL,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,PRIMARY KEY(candidate_user_id,check_code),CONSTRAINT fk_check_candidate FOREIGN KEY(candidate_user_id) REFERENCES users(id) ON DELETE CASCADE,CONSTRAINT fk_check_staff FOREIGN KEY(updated_by) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS candidate_preferences (candidate_user_id BIGINT UNSIGNED NOT NULL,best_role VARCHAR(120) NULL,other_roles VARCHAR(500) NULL,preferred_location VARCHAR(160) NULL,work_arrangement ENUM('live_in','live_out','either') NOT NULL DEFAULT 'either',employment_type ENUM('full_time','part_time','contract','any') NOT NULL DEFAULT 'any',minimum_salary DECIMAL(12,2) NULL,expected_salary DECIMAL(12,2) NULL,available_from DATE NULL,willing_to_relocate BOOLEAN NOT NULL DEFAULT FALSE,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,PRIMARY KEY(candidate_user_id),CONSTRAINT fk_pref_candidate FOREIGN KEY(candidate_user_id) REFERENCES users(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS applications (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,candidate_user_id BIGINT UNSIGNED NOT NULL,job_id BIGINT UNSIGNED NULL,staffing_request_id BIGINT UNSIGNED NULL,status ENUM('received','under_review','documents_needed','verification','matched','interview','awaiting_placement','selected','placed','not_selected','talent_pool') NOT NULL DEFAULT 'received',created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,PRIMARY KEY(id),UNIQUE KEY uq_candidate_job(candidate_user_id,job_id),KEY idx_application_candidate(candidate_user_id,status),CONSTRAINT fk_application_candidate FOREIGN KEY(candidate_user_id) REFERENCES users(id) ON DELETE CASCADE,CONSTRAINT fk_application_job FOREIGN KEY(job_id) REFERENCES jobs(id) ON DELETE SET NULL,CONSTRAINT fk_application_request FOREIGN KEY(staffing_request_id) REFERENCES staffing_requests(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS application_status_history (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,application_id BIGINT UNSIGNED NOT NULL,previous_status VARCHAR(40) NULL,new_status VARCHAR(40) NOT NULL,candidate_note VARCHAR(1000) NULL,changed_by BIGINT UNSIGNED NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY(id),KEY idx_history_application(application_id,created_at),CONSTRAINT fk_history_application FOREIGN KEY(application_id) REFERENCES applications(id) ON DELETE CASCADE,CONSTRAINT fk_history_staff FOREIGN KEY(changed_by) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS candidate_messages (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,candidate_user_id BIGINT UNSIGNED NOT NULL,title VARCHAR(180) NOT NULL,message TEXT NOT NULL,message_type ENUM('information','action_required','interview','congratulations','placement_instruction') NOT NULL DEFAULT 'information',is_read BOOLEAN NOT NULL DEFAULT FALSE,visible_from DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,created_by BIGINT UNSIGNED NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY(id),KEY idx_candidate_messages(candidate_user_id,is_read,visible_from),CONSTRAINT fk_message_candidate FOREIGN KEY(candidate_user_id) REFERENCES users(id) ON DELETE CASCADE,CONSTRAINT fk_message_staff FOREIGN KEY(created_by) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS job_details (job_id BIGINT UNSIGNED NOT NULL,duties TEXT NOT NULL,expectations TEXT NOT NULL,experience_required VARCHAR(500) NULL,salary_min DECIMAL(12,2) NULL,salary_max DECIMAL(12,2) NULL,schedule VARCHAR(500) NULL,accommodation ENUM('provided','not_provided','not_applicable') NOT NULL DEFAULT 'not_applicable',work_arrangement ENUM('live_in','live_out','either','not_applicable') NOT NULL DEFAULT 'not_applicable',benefits VARCHAR(1000) NULL,PRIMARY KEY(job_id),CONSTRAINT fk_job_details FOREIGN KEY(job_id) REFERENCES jobs(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS employer_shortlists (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,employer_user_id BIGINT UNSIGNED NOT NULL,staffing_request_id BIGINT UNSIGNED NOT NULL,status ENUM('draft','shared','responded','closed') NOT NULL DEFAULT 'draft',shared_at DATETIME NULL,created_by BIGINT UNSIGNED NOT NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY(id),KEY idx_shortlist_employer(employer_user_id,status),CONSTRAINT fk_shortlist_employer FOREIGN KEY(employer_user_id) REFERENCES users(id),CONSTRAINT fk_shortlist_request FOREIGN KEY(staffing_request_id) REFERENCES staffing_requests(id),CONSTRAINT fk_shortlist_staff FOREIGN KEY(created_by) REFERENCES users(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS shortlist_candidates (shortlist_id BIGINT UNSIGNED NOT NULL,candidate_user_id BIGINT UNSIGNED NOT NULL,public_summary TEXT NOT NULL,match_score TINYINT UNSIGNED NOT NULL,match_reasons JSON NOT NULL,employer_response ENUM('pending','preferred','interview_requested','not_preferred') NOT NULL DEFAULT 'pending',employer_note VARCHAR(1000) NULL,responded_at DATETIME NULL,PRIMARY KEY(shortlist_id,candidate_user_id),CONSTRAINT fk_shortlist_item FOREIGN KEY(shortlist_id) REFERENCES employer_shortlists(id) ON DELETE CASCADE,CONSTRAINT fk_shortlist_candidate FOREIGN KEY(candidate_user_id) REFERENCES users(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS candidate_private_details (candidate_user_id BIGINT UNSIGNED NOT NULL,date_of_birth DATE NULL,education_level VARCHAR(120) NULL,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,PRIMARY KEY(candidate_user_id),CONSTRAINT fk_private_candidate FOREIGN KEY(candidate_user_id) REFERENCES users(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS saved_jobs (candidate_user_id BIGINT UNSIGNED NOT NULL,job_id BIGINT UNSIGNED NOT NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY(candidate_user_id,job_id),CONSTRAINT fk_saved_candidate FOREIGN KEY(candidate_user_id) REFERENCES users(id) ON DELETE CASCADE,CONSTRAINT fk_saved_job FOREIGN KEY(job_id) REFERENCES jobs(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS financial_transactions (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,payer_user_id BIGINT UNSIGNED NOT NULL,service_price_id BIGINT UNSIGNED NULL,reference_code VARCHAR(50) NOT NULL,purpose VARCHAR(180) NOT NULL,amount DECIMAL(12,2) NOT NULL,currency CHAR(3) NOT NULL DEFAULT 'KES',method_code VARCHAR(40) NULL,status ENUM('pending','processing','paid','failed','cancelled','refunded') NOT NULL DEFAULT 'pending',external_reference VARCHAR(120) NULL,paid_at DATETIME NULL,recorded_by BIGINT UNSIGNED NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY(id),UNIQUE KEY uq_financial_reference(reference_code),KEY idx_financial_payer(payer_user_id,created_at),CONSTRAINT fk_financial_payer FOREIGN KEY(payer_user_id) REFERENCES users(id),CONSTRAINT fk_financial_price FOREIGN KEY(service_price_id) REFERENCES service_prices(id) ON DELETE SET NULL,CONSTRAINT fk_financial_method FOREIGN KEY(method_code) REFERENCES payment_methods(method_code) ON DELETE SET NULL,CONSTRAINT fk_financial_staff FOREIGN KEY(recorded_by) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS receipts (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,transaction_id BIGINT UNSIGNED NOT NULL,receipt_number VARCHAR(50) NOT NULL,issued_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,issued_by BIGINT UNSIGNED NULL,PRIMARY KEY(id),UNIQUE KEY uq_receipt_number(receipt_number),UNIQUE KEY uq_receipt_transaction(transaction_id),CONSTRAINT fk_receipt_transaction FOREIGN KEY(transaction_id) REFERENCES financial_transactions(id),CONSTRAINT fk_receipt_staff FOREIGN KEY(issued_by) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS content_posts (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,slug VARCHAR(180) NOT NULL,title VARCHAR(180) NOT NULL,excerpt VARCHAR(320) NOT NULL,content MEDIUMTEXT NOT NULL,status ENUM('draft','pending_approval','published','rejected') NOT NULL DEFAULT 'draft',author_user_id BIGINT UNSIGNED NOT NULL,reviewed_by BIGINT UNSIGNED NULL,review_note VARCHAR(500) NULL,published_at DATETIME NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,PRIMARY KEY(id),UNIQUE KEY uq_content_slug(slug),KEY idx_content_status(status,published_at),CONSTRAINT fk_content_author FOREIGN KEY(author_user_id) REFERENCES users(id),CONSTRAINT fk_content_reviewer FOREIGN KEY(reviewed_by) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS contract_templates (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,name VARCHAR(160) NOT NULL,version INT UNSIGNED NOT NULL DEFAULT 1,terms_html MEDIUMTEXT NOT NULL,is_active BOOLEAN NOT NULL DEFAULT TRUE,updated_by BIGINT UNSIGNED NOT NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,PRIMARY KEY(id),KEY idx_contract_template_active(is_active),CONSTRAINT fk_contract_template_admin FOREIGN KEY(updated_by) REFERENCES users(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS employment_contracts (id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,contract_number VARCHAR(50) NOT NULL,template_id BIGINT UNSIGNED NOT NULL,template_version INT UNSIGNED NOT NULL,employer_user_id BIGINT UNSIGNED NOT NULL,candidate_user_id BIGINT UNSIGNED NOT NULL,job_id BIGINT UNSIGNED NULL,staffing_request_id BIGINT UNSIGNED NULL,placement_id BIGINT UNSIGNED NULL,role_title VARCHAR(180) NOT NULL,start_date DATE NOT NULL,end_date DATE NULL,terms_snapshot MEDIUMTEXT NOT NULL,status ENUM('draft','sent','employer_signed','candidate_signed','fully_signed','cancelled','expired') NOT NULL DEFAULT 'draft',employer_signed_name VARCHAR(180) NULL,employer_signed_at DATETIME NULL,candidate_signed_name VARCHAR(180) NULL,candidate_signed_at DATETIME NULL,created_by BIGINT UNSIGNED NOT NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,updated_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,PRIMARY KEY(id),UNIQUE KEY uq_contract_number(contract_number),KEY idx_contract_employer(employer_user_id,status),KEY idx_contract_candidate(candidate_user_id,status),CONSTRAINT fk_contract_template FOREIGN KEY(template_id) REFERENCES contract_templates(id),CONSTRAINT fk_contract_employer FOREIGN KEY(employer_user_id) REFERENCES users(id),CONSTRAINT fk_contract_candidate FOREIGN KEY(candidate_user_id) REFERENCES users(id),CONSTRAINT fk_contract_job FOREIGN KEY(job_id) REFERENCES jobs(id) ON DELETE SET NULL,CONSTRAINT fk_contract_request FOREIGN KEY(staffing_request_id) REFERENCES staffing_requests(id) ON DELETE SET NULL,CONSTRAINT fk_contract_placement FOREIGN KEY(placement_id) REFERENCES placements(id) ON DELETE SET NULL,CONSTRAINT fk_contract_creator FOREIGN KEY(created_by) REFERENCES users(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS content_post_images (post_id BIGINT UNSIGNED NOT NULL,storage_key VARCHAR(255) NOT NULL,mime_type VARCHAR(60) NOT NULL,file_size INT UNSIGNED NOT NULL,created_at DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY(post_id),CONSTRAINT fk_content_image_post FOREIGN KEY(post_id) REFERENCES content_posts(id) ON DELETE CASCADE) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
